import{o as p,c as e,C as t}from"./framework.7a6825f4.js";const a='{"title":"Глава 14","description":"","frontmatter":{"title":"Глава 14","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-08-01T00:00:00.000Z"},"headers":[{"level":2,"title":"Четырнадцатая глава","slug":"четырнадцатая-гnава"}],"relativePath":"texts/malini-vijayottara/14.md","lastUpdated":1624915667164}',r={},l=t('<h2 id="четырнадцатая-гnава"><a class="header-anchor" href="#четырнадцатая-гnава" aria-hidden="true">#</a> Четырнадцатая глава</h2><p>Теперь поведаю о дхаранах на танматрах, по порядку, начиная с запаха, и о плодах их реализации ..1.</p><p>Следует созерцать пребывающую в на вершине ноздревых отверстий гандха танматру, желтую, четырехугольную, подобную горе, отмеченную знаками ваджры ..2.</p><p>Йогин, который созерцает ее более десяти дней не отвлекаясь умом, какой запах не сможет обрести, двоякий и многообразный?.3.</p><p>Затем за один сезон для него благой запах станет устойчивым. За шесть месяцев он станет самим запахом ..4.</p><p>Какой бы и где не проявлялся запах, на нем следует сосредотачиваться. За три года он обретет сиддхи управления пятью элементами ..5.</p><p>Выше следует созерцать форму Атмана в сердце. За три года (йогин) обретет знание уровня запаха ..6.</p><p>Созерцающий слегка сияющий (образ запаха) лишенный мандалы, узрит всех обитателей (входящих) в уровень запаха ..7.</p><p>Созерцая там названный образ таттвы земли, (йогин) обретет единство с ней, пребывая, как ранее, на втором уровне ..8.</p><p>Созерцая там свою форму, сияющую, пребывающую ниже, он обретет владычество над ней описанным выше путем ..9.</p><p>Затем следует все созерцать (методом), подобным описанному для выше таттвы земли. Затем выше (йогин) обретет плод ее изначальной формы, пребывающий на уровне запаха ..10.</p><p>Теперь поведаю о дхаране образа вкуса используемое йогинами, благодаря ей у йогинов обретается вездесущность ..11.</p><p>Следует созерцать воду, являющуюся с пузырями пребывающую на кончике языка, как танматру, содержащуюся на кончике языка ..12.</p><p>Прохладная, обладающая шестью вкусами, созерцаемая вместе с пребывающей с ней ее внутренней сущностью. За месяц у него появятся ее сладкий вкус ..13.</p><p>Когда он обретет сладость, оставив соленный и прочие, (вкусы), тогда, несомненно, йогин за шесть месяцев станет победителем смерти ..14.</p><p>Свободный от старости и болезней, наделенный черными волосами, он будет жить пока существует луна, звезды и солнце ..15.</p><p>Созерцая его в изначальной форме, в описанном прежде образе пузырей, (йогин) обретает постижение уровня воды. Что может быть удивительней?.16.</p><p>Эта соединенная с молненией дхьяна, лишенная опоры производит за (несколько) лет все, что содержится на уровне воды ..17.</p><p>Созерцая описанный выше образ таттвы воды, (йогин) достигает всего, рожденного на уровне вкуса ..18.</p><p>Теперь поведаю о благой дхаране, наделяющей божественным видением, наделяющей всеми сиддхи, содержащейся в рупа танматре ..19.</p><p>Йогину следует, пребывая в уединенном месте, немигающим взглядом видеть все в виде осеннего облака;.20.</p><p>Так сосредотачивая ум, пребывать там десять дней до тех пор пока не увидит чрезвычайно тонкую бинду ..21.</p><p>Некоторые там белые, некоторые красные, желтые, другие синие- увидев их, следует предельно сосредоточить ум, не отвлекая сознание ни на что иное ..22.</p><p>Через шесть месяцев он увидит в них великое множество форм, за три года они, вместе с сияющим светом, станут устойчивыми ..23.</p><p>Благодаря такой практике за два года, он увидит образы бимба, через за год, он увидит огонь, за шесть месяцев – образ пуруши ..24.</p><p>За три месяца – проникающий огонь, за месяц – всепроникающий. За описанную выше последовательность времени, (явится) уровень формы;.25.</p><p>(Йогин) обретет плод их всех, у нег о появится божественное зрение. Такова лишенная представлений дхарана, проявляющаяся от ее выполнения ..26.</p><p>В своих пятнадцать отдельных видах, она является сама. Поскольку она- самодостаточна, следует, не сомневаясь, ее практиковать. К чему множество прочих писаний?.27.</p><p>Теперь поведаю Тебе другую дхарану, состоящую из осязания, благодаря которой йогин обретает ваджрное тело ..28.</p><p>Следует созерцать себя (Атман) пребывающим внутри шестиугольной мандалы, каждая часть которой, подобно цветку кукшма анджнана, наполнена светом ..29.</p><p>Затем, всего за десять дней, о Деви, он станет (единым) с прикосновением муравья, созерцая его ..30.</p><p>Он будет пребывать в ваджрном теле, он обретет его, как было сказано ранее, созерцая его в первичной форме, в образе мандалы ..31.</p><p>Обретя знания деятельности <em>спарша таттвы</em>, кем он может быть побежден? Для обретения господства над ней следует созерцать себя в мандале ..32.</p><p>Благодаря ее реализации, он станет знающим все прикосновения. Закрыв уши, пусть он старательно вслушивается при закрытых глазах ..33.</p><p>Если он услышит великий гром, на нем следует сосредоточиться. За десять дней у него явится (знание) утробного огня ..34.</p><p>За шесть месяцев у него появится знание слышимого издалека. Пока оно не наступило окончательно, следует созерцать медленно и постепенно (вслушиваясь) ..35.</p><p>Благодаря этой практике, не отвлекаясь умом ни на что иное, постигается Сущность <em>сакалы.</em> (Благодаря ей, йогин) обретет знание уровня звука, и будет пребывать в нем устойчиво ..36.</p><p>Какой бы звук он не услышал вначале, в конце него- звук, подобный раковине, есть форма пралая кала, его следует практиковать желающим его плода ..37.</p><p>Когда он превзойдет ее, (и достигнет) оболочки другого звука, он именуется виджнанакала, в нем он будет непобедим ..38.</p><p>(Звук) доставляющий радость уму, который созерцается вслед за ним, известен йогина, желающим йоги, как мантра ..39.</p><p>Затем слышится другой звук, подобный спокойному гудению раковины. Это именуется (уровенем) мантреши, дающей плод всех сиддхи ..40.</p><p>Звук который появляется после прекращения гудения раковины, есть уровень мантреши, великая причина сиддхи ..41.</p><p>Благодаря непрекращающему гудению нады в небе, подобной вине, он достигнет освобождения. Звук подобный ей известен как обитель Шамбху ..42.</p><p>По отдельности и по порядку, следует практиковать их всех, тогда всезнающий достигнет всех сиддхи, пребывая в окружении звука. Итак, Тебе названы дхарны пяти танматр ..43.__ [small]Такова в священной «Малини виджайоттара тантре» четырнадцатая глава [/small]</p>',44);r.render=function(t,a,r,i,s,n){return p(),e("div",null,[l])};export default r;export{a as __pageData};
